// --- types.d.ts ---
export interface ForecastDay {
  day: string;
  icon: string;
  high: number;
  low: number;
}

export interface WeatherProps {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit?: "C" | "F";
  forecast: ForecastDay[];
}

export interface WeatherHeaderProps {
  city: string;
  temperatureDisplay: string;
  condition: string;
}

export interface WeatherDetailsProps {
  humidity: number;
  windSpeed: number;
  unit: string;
}

export interface ForecastStripProps {
  forecast: ForecastDay[];
  unit: string;
}

export interface ForecastItemProps {
  day: string;
  icon: string;
  high: number;
  low: number;
  unit: string;
}

export interface WeatherHookReturn {
  formattedTemp: string;
  formattedWind: string;
  activeUnit: string;
  weatherAriaLabel: string;
}


// --- constants.ts ---
/**
 * Weather Component Constants
 */

import { WeatherProps } from './types';

/**
 * Mapping of temperature units to their display symbols.
 */
export const UNIT_SYMBOLS = {
  C: '°C',
  F: '°F',
} as const;

/**
 * Default temperature unit if none is provided.
 */
export const DEFAULT_UNIT: NonNullable<WeatherProps['unit']> = 'C';

/**
 * Mapping of common weather conditions to emoji/icon identifiers.
 */
export const CONDITION_ICONS: Record<string, string> = {
  Sunny: '☀️',
  Cloudy: '☁️',
  Rainy: '🌧️',
  Snowy: '❄️',
  'Partly Cloudy': '⛅',
  Thunderstorm: '⛈️',
  Clear: '☀️',
  Mist: '🌫️',
  Drizzle: '🌦️',
};

/**
 * Mapping of metric/imperial units to wind speed labels.
 */
export const WIND_SPEED_UNITS = {
  C: 'km/h',
  F: 'mph',
} as const;

/**
 * Template function for weather accessibility label.
 * @param city - The name of the city
 * @param temperature - The numeric or formatted temperature
 * @param condition - The weather condition description
 */
export const WEATHER_ARIA_LABEL_TEMPLATE = (
  city: string,
  temperature: string | number,
  condition: string
): string => `Current weather in ${city}: ${temperature} degrees, ${condition}`;

/**
 * Static labels for UI sections.
 */
export const LABEL_HUMIDITY = 'Humidity';
export const LABEL_WIND = 'Wind Speed';
export const LABEL_FORECAST = 'Forecast';


// --- hooks.ts ---
import { useMemo } from 'react';
import type { WeatherProps, WeatherHookReturn } from './types';

/**
 * Custom hook for the Weather Card component that handles 
 * data transformation and accessibility strings.
 */
export function useWeather(props: WeatherProps): WeatherHookReturn {
  // Establish a local variable for the active unit, defaulting to "C"
  const activeUnit = props.unit || 'C';

  // Format temperature as "XX°C" or "XX°F"
  const formattedTemp = useMemo(() => {
    return `${props.temperature}°${activeUnit}`;
  }, [props.temperature, activeUnit]);

  // Format wind speed with correct suffix based on unit
  const formattedWind = useMemo(() => {
    const suffix = activeUnit === 'F' ? ' mph' : ' km/h';
    return `${props.windSpeed}${suffix}`;
  }, [props.windSpeed, activeUnit]);

  // Construct descriptive string for screen readers
  const weatherAriaLabel = useMemo(() => {
    const { city, condition, temperature, humidity } = props;
    return `Current weather in ${city}: ${condition}, ${temperature} degrees ${activeUnit}. Humidity: ${humidity}%, Wind speed: ${formattedWind}.`;
  }, [
    props.city,
    props.condition,
    props.temperature,
    props.humidity,
    activeUnit,
    formattedWind,
  ]);

  return {
    formattedTemp,
    formattedWind,
    activeUnit,
    weatherAriaLabel,
  };
}


// --- components/WeatherHeader.tsx ---
// components/WeatherHeader.tsx — reusable sub-component
import React from 'react';
import { Stack, Heading, Text } from '@ggui-ai/design/primitives';
import type { WeatherHeaderProps } from './types';

export function WeatherHeader({ city, temperatureDisplay, condition }: WeatherHeaderProps) {
  return (
    <Stack
      gap="var(--ggui-spacing-2)"
      aria-live="polite"
      style={{ marginBottom: 'var(--ggui-spacing-4)' }}
    >
      <Heading level={2} color="var(--ggui-color-onSurface)">
        {city}
      </Heading>
      <div aria-label={`${temperatureDisplay}, ${condition}`}>
        <Text
          variant="bodyLarge"
          style={{ fontSize: '3rem', fontWeight: 'bold' }}
        >
          {temperatureDisplay}
        </Text>
        <Text
          variant="body"
          color="var(--ggui-color-onSurfaceVariant)"
        >
          {condition}
        </Text>
      </div>
    </Stack>
  );
}


// --- components/WeatherDetails.tsx ---
import React from 'react';
import { Box, Row, Stack, Text, Icon } from '@ggui-ai/design/primitives';
import type { WeatherDetailsProps } from './types';

export function WeatherDetails({ humidity, windSpeed, unit }: WeatherDetailsProps) {
  return (
    <Box paddingY="var(--ggui-spacing-4)" aria-label="Weather details">
      <Row justify="between" gap="var(--ggui-spacing-6)">
        {/* Humidity Metric */}
        <Row align="center" gap="var(--ggui-spacing-3)">
          <Icon
            name="water_drop"
            color="var(--ggui-color-onSurfaceVariant)"
            aria-hidden="true"
          />
          <Stack gap={0}>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
              Humidity
            </Text>
            <Text variant="bodyLarge" color="var(--ggui-color-onSurface)">
              {humidity}%
            </Text>
          </Stack>
        </Row>

        {/* Wind Speed Metric */}
        <Row align="center" gap="var(--ggui-spacing-3)">
          <Icon
            name="air"
            color="var(--ggui-color-onSurfaceVariant)"
            aria-hidden="true"
          />
          <Stack gap={0}>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
              Wind Speed
            </Text>
            <Text variant="bodyLarge" color="var(--ggui-color-onSurface)">
              {windSpeed} {unit === 'C' ? 'km/h' : 'mph'}
            </Text>
          </Stack>
        </Row>
      </Row>
    </Box>
  );
}


// --- components/ForecastStrip.tsx ---
import React from 'react';
import { Stack, Text, Box, Divider, Row } from '@ggui-ai/design/primitives';
import type { ForecastStripProps } from './types';

export function ForecastStrip({ forecast, unit }: ForecastStripProps) {
  return (
    <section aria-label="5-day forecast">
      <Divider color="var(--ggui-color-outlineVariant)" margin="var(--ggui-spacing-4)" />

      <Box style={{ overflowX: 'auto', width: '100%' }}>
        <Row 
          justify="between" 
          gap="var(--ggui-spacing-4)" 
          style={{ minWidth: 'max-content', paddingBottom: 'var(--ggui-spacing-2)' }}
        >
          {forecast.map((item, index) => (
            <Stack 
              key={`${item.day}-${index}`} 
              align="center" 
              gap={2}
              style={{ minWidth: '64px' }}
            >
              <Text 
                variant="label" 
                color="var(--ggui-color-onSurfaceVariant)"
              >
                {item.day}
              </Text>

              <Text 
                variant="bodyLarge" 
                aria-hidden="true"
              >
                {item.icon}
              </Text>

              <Stack direction="horizontal" gap={4} align="center">
                <Text 
                  variant="bodySmall" 
                  weight="bold" 
                  color="var(--ggui-color-onSurface)"
                  aria-label={`High ${item.high} degrees ${unit}`}
                >
                  {item.high}°{unit}
                </Text>
                <Text 
                  variant="bodySmall" 
                  color="var(--ggui-color-onSurfaceVariant)"
                  aria-label={`Low ${item.low} degrees ${unit}`}
                >
                  {item.low}°{unit}
                </Text>
              </Stack>
            </Stack>
          ))}
        </Row>
      </Box>
    </section>
  );
}


// --- ui.tsx ---
import React from 'react';
import { Card, Stack, Divider } from '@ggui-ai/design/primitives';
import type { WeatherProps } from './types';
import { WeatherHeader, WeatherDetails, ForecastStrip } from './components';
import { useWeather } from './hooks';

/**
 * WeatherCard Component
 * 
 * The main entry point for the weather display, showing current conditions
 * and a forecast strip.
 */
export function WeatherCard(props: WeatherProps) {
  const {
    city,
    temperature,
    condition,
    humidity,
    windSpeed,
    unit = 'C',
    forecast,
  } = props;

  const {
    formattedTemp,
    activeUnit,
    weatherAriaLabel,
  } = useWeather({
    temperature,
    unit,
    windSpeed,
    city,
    condition,
  });

  return (
    <div
      role="region"
      aria-label={weatherAriaLabel}
      style={{ maxWidth: '400px', margin: '0 auto', width: '100%' }}
    >
      <Card padding="var(--ggui-spacing-4)">
      <Stack gap="var(--ggui-spacing-6)" align="stretch">
        <WeatherHeader
          city={city}
          temperatureDisplay={formattedTemp}
          condition={condition}
        />

        <WeatherDetails
          humidity={humidity}
          windSpeed={windSpeed}
          unit={activeUnit}
        />

        <Divider margin="0" />

        <ForecastStrip
          forecast={forecast}
          unit={activeUnit}
        />
      </Stack>
      </Card>
    </div>
  );
}


// --- render.tsx ---
// render.tsx — entry point
import React from 'react';
import type { Props } from './types';
import { useComponent } from './hooks';
import { ComponentUI } from './ui';

export default function Component(props: Props) {
  const state = useComponent(props);
  return <ComponentUI {...props} {...state} />;
}
